from datetime import datetime

from pydantic import Field

from maascommon.enums.operations import (
    OperationStatus,
    OperationTaskStatus,
    OperationType,
)
from maasservicelayer.models.base import ResourceBuilder, UNSET, Unset


class OperationBuilder(ResourceBuilder):
    """Autogenerated from utilities/generate_builders.py.

    You can still add your custom methods here, they won't be overwritten by
    the generated code.
    """

    created: datetime | Unset = Field(default=UNSET)
    current_task: str | None | Unset = Field(default=UNSET)
    finished: datetime | None | Unset = Field(default=UNSET)
    is_bulk: bool | Unset = Field(default=UNSET)
    op_type: OperationType | Unset = Field(default=UNSET)
    parameters: dict | None | Unset = Field(default=UNSET)
    parent_id: str | None | Unset = Field(default=UNSET)
    resource_id: int | None | Unset = Field(default=UNSET)
    resource_type: str | None | Unset = Field(default=UNSET)
    result_errors: dict | None | Unset = Field(default=UNSET)
    started: datetime | None | Unset = Field(default=UNSET)
    status: OperationStatus | Unset = Field(default=UNSET)
    updated: datetime | Unset = Field(default=UNSET)
    user_id: int | None | Unset = Field(default=UNSET)
    uuid: str | Unset = Field(default=UNSET)


